const EXTRA_SECTION_POOL=[
(c)=>{const s=getRegionStats(c.loc,c.parent);if(!s)return null;const h=c.h;return{h:_SEC_ENV_H[h%_SEC_ENV_H.length](c,s),p:_SEC_ENV_B[(h>>>3)%_SEC_ENV_B.length](c,s)};},
(c)=>{const ctx=getRegionCtx(c.loc,c.parent);if(!ctx.gugun)return null;if(typeof DONG_DATA==='undefined'||!DONG_DATA[ctx.gugun])return null;const d=DONG_DATA[ctx.gugun];if(d.length===0)return null;const h=c.h;return{h:_SEC_DONG_H[h%_SEC_DONG_H.length](c,ctx.gugun,d),p:_SEC_DONG_B[(h>>>3)%_SEC_DONG_B.length](c,ctx.gugun,d)};},
(c)=>{const hints=_SEC_LV_HINT[c.level]||_SEC_LV_HINT['중등'];const h=c.h;const hint=hints[h%hints.length];return{h:_SEC_LV_H[(h>>>2)%_SEC_LV_H.length](c),p:_SEC_LV_B[(h>>>5)%_SEC_LV_B.length](c,hint)};},
(c)=>{const h=c.h;return{h:_SEC_SELF_H[h%_SEC_SELF_H.length](c),p:_SEC_SELF_B[(h>>>3)%_SEC_SELF_B.length](c)};},
];
function pickRegionSchools(loc,level,parent,n,rng){const ctx=getRegionCtx(loc,parent);if(level==='중등'||level==='고등'){const idx=getSidoIdxFromShort(ctx.sido);if(idx<0)return null;const sl=level==='중등'?'middle':'high';const all=getSchoolsBySidoGugun(sl,idx,ctx.gugun);if(all.length===0)return null;const names=all.map(s=>s.school[0]);const picked=pickN(names,Math.min(n,names.length),rng);return{count:all.length,picked,sl,dispRegion:ctx.gugun||ctx.sido};}if(level==='초등'){if(!ctx.gugun)return null;if(typeof DONG_DATA==='undefined'||!DONG_DATA[ctx.gugun])return null;const dongs=DONG_DATA[ctx.gugun];const all=[...new Set(dongs.map(d=>d.replace(/[동읍면리]$/,'')+'초등학교'))];if(all.length===0)return null;const picked=pickN(all,Math.min(n,all.length),rng);return{count:all.length,picked,sl:'elem',dispRegion:ctx.gugun};}return null;}
const SCHOOL_SECTION_POOL=[
(reg,n,lv,names,subj)=>`${reg}에는 총 ${n}개의 ${lv}가 있으며, 대표적으로 ${names.join(', ')} 등이 있습니다. 학교마다 시험 출제 경향과 내신 평가 방식이 다르기 때문에, 우리 아이가 다니는 학교에 맞춘 ${subj} 과외가 가장 효과적입니다.`,
(reg,n,lv,names,subj)=>`${reg}의 ${lv} ${n}곳 중 ${names.slice(0,3).join('·')} 등은 학부모들이 자주 문의하는 학교입니다. 각 학교의 ${subj} 진도 차이와 내신 출제 패턴을 정확히 파악한 과외 선생님을 만나는 것이 성적 향상의 지름길입니다.`,
(reg,n,lv,names,subj)=>`${lv} 기준 ${n}개교가 분포한 ${reg}. ${names.join(', ')} 등 우리 학교에 맞는 ${subj} 학습 전략이 필요합니다. 같은 학년이라도 학교별 시험 범위와 난이도가 다르기 때문에 1:1 맞춤 수업이 효율적이에요.`,
(reg,n,lv,names,subj)=>`${reg}에서 ${subj} 과외를 찾는다면 우리 학교 출제 경향을 아는 선생님이 우선입니다. 이 지역 ${lv} ${n}곳(${names.slice(0,4).join(', ')} 등) 학생들이 자주 의뢰하는 만큼, 학교별 데이터 보유 여부를 꼭 확인하세요.`,
(reg,n,lv,names,subj)=>`이 지역 ${lv}는 ${n}곳입니다. ${names.join(', ')} 등 학교마다 평가 방식과 진도가 달라, 학교명을 알려주고 그에 맞는 ${subj} 커리큘럼을 짜주는 선생님을 선택하면 성적 향상 속도가 빨라집니다.`,
];
function getSchools(level) { return level === 'middle' ? SCHOOLS_MID : SCHOOLS_HIGH; }
function getSidoFromIdx(idx) { return SIDO_LIST[idx] || ''; }
function getSidoShort(sido) { return sido.replace(/특별시|광역시|특별자치시|특별자치도|도$/g, ''); }
function levelName(level) { return level === 'middle' ? '중학교' : level === 'high' ? '고등학교' : '초등학교'; }
function levelColor(level) { return level === 'middle' ? '#8b5cf6' : '#ef4444'; }
function levelBg(level) { return level === 'middle' ? '#f5f3ff' : '#fef2f2'; }
function findSchoolByName(name) {
  for (let i = 0; i < SCHOOLS_MID.length; i++) if (SCHOOLS_MID[i][0] === name) return {level:'middle', idx:i, school:SCHOOLS_MID[i]};
  for (let i = 0; i < SCHOOLS_HIGH.length; i++) if (SCHOOLS_HIGH[i][0] === name) return {level:'high', idx:i, school:SCHOOLS_HIGH[i]};
  return null;
}
function getSchoolsBySidoGugun(level, sidoIdx, gugun) {
  const schools = getSchools(level);
  const result = [];
  for (let i = 0; i < schools.length; i++) {
    if (schools[i][1] === sidoIdx && (gugun === null || schools[i][2] === gugun)) {
      result.push({idx: i, school: schools[i]});
    }
  }
  return result;
}
function getGugunsBySido(level, sidoIdx) {
  const schools = getSchools(level);
  const map = {};
  for (const s of schools) {
    if (s[1] === sidoIdx) map[s[2]] = (map[s[2]] || 0) + 1;
  }
  return Object.entries(map).map(([g, c]) => ({gugun: g, count: c})).sort((a,b)=>a.gugun.localeCompare(b.gugun, 'ko'));
}

