const INDEXNOW_KEY = 'bc7021aaa2ada0c01d58334f8753cb9e';
const SITE_HOST = 'anhani.com';

// ===== v90: 자동 색인 시스템 (매일 오전 9시 KST Cron) =====
// Tier 1: 학군 핵심 (강남/서초/송파/성남시 분당·판교)
const TIER1_SIGUNGUS = {
  '서울': ['강남구', '서초구', '송파구'],
  '경기': ['성남시']  // 분당구·수정구·중원구 모두 포함
};
// Tier 2: 서울 일반구 + 6대 광역시
const TIER2_SIDOS_FULL = ['부산', '대구', '인천', '광주', '대전', '울산'];

// 우선순위 URL 큐 빌더 (~9000개 핵심 URL, 6개월 1회전)
function buildPriorityQueue() {
  const urls = [];
  const sub8 = ['국어','영어','수학','사회','과학','코딩','검정고시','논술'];

  // 1. 코어 인덱스 (~10개)
  ['/', '/지역별', '/과목별', '/학년별', '/학교급별', '/서비스', '/학습가이드',
   '/conversation/english', '/conversation/chinese', '/conversation/japanese'].forEach(p => urls.push(p));

  // 2. Tier 1 시군구 + 동 + 동 카테고리 (~120 + 학년/과목 카테고리 1500)
  for (const sd of Object.keys(TIER1_SIGUNGUS)) {
    for (const sg of TIER1_SIGUNGUS[sd]) {
      const esd = encodeURIComponent(sd), esg = encodeURIComponent(sg);
      urls.push(`/지역별/${esd}/${esg}`);
      const dongs = [...getDongs(sd, sg), ...(EUP_MYEON[sg] || [])];
      for (const d of dongs) {
        const ed = encodeURIComponent(d);
        urls.push(`/지역별/${esd}/${esg}/${ed}`);
        // Tier 1 동 카테고리 (학년 4개 + 과목 8개) — 검색량 매우 높음
        for (const lvl of ['초등','중등','고등','검정고시']) {
          urls.push(`/지역별/${esd}/${esg}/${ed}/학년/${encodeURIComponent(lvl)}`);
        }
        for (const s of sub8) {
          urls.push(`/지역별/${esd}/${esg}/${ed}/과목/${encodeURIComponent(s)}`);
        }
      }
    }
  }

  // 3. Tier 2 서울 나머지 구 + 동 (~400개)
  if (REGIONS['서울']) {
    for (const sg of REGIONS['서울']) {
      if (TIER1_SIGUNGUS['서울'].includes(sg)) continue;
      const esg = encodeURIComponent(sg);
      urls.push(`/지역별/${encodeURIComponent('서울')}/${esg}`);
      const dongs = [...getDongs('서울', sg), ...(EUP_MYEON[sg] || [])];
      for (const d of dongs) urls.push(`/지역별/${encodeURIComponent('서울')}/${esg}/${encodeURIComponent(d)}`);
    }
  }

  // 4. Tier 2 경기 핵심 시군구 (~500개)
  const gyeonggiKey = ['수원시','용인시','고양시','안양시','과천시','광명시','부천시','하남시','화성시'];
  if (REGIONS['경기']) {
    for (const sg of gyeonggiKey) {
      if (!REGIONS['경기'].includes(sg)) continue;
      const esg = encodeURIComponent(sg);
      urls.push(`/지역별/${encodeURIComponent('경기')}/${esg}`);
      const dongs = [...getDongs('경기', sg), ...(EUP_MYEON[sg] || [])];
      for (const d of dongs) urls.push(`/지역별/${encodeURIComponent('경기')}/${esg}/${encodeURIComponent(d)}`);
    }
  }

  // 5. Tier 2 광역시 (~700개)
  for (const sd of TIER2_SIDOS_FULL) {
    if (!REGIONS[sd]) continue;
    const esd = encodeURIComponent(sd);
    for (const sg of REGIONS[sd]) {
      const esg = encodeURIComponent(sg);
      urls.push(`/지역별/${esd}/${esg}`);
      const dongs = [...getDongs(sd, sg), ...(EUP_MYEON[sg] || [])];
      for (const d of dongs) urls.push(`/지역별/${esd}/${esg}/${encodeURIComponent(d)}`);
    }
  }

  // 6. Tier 3: 경기 나머지 시군구 (~2500개) — 6개월 사이클 채우기용
  if (REGIONS['경기']) {
    for (const sg of REGIONS['경기']) {
      if (gyeonggiKey.includes(sg)) continue;
      const esg = encodeURIComponent(sg);
      urls.push(`/지역별/${encodeURIComponent('경기')}/${esg}`);
      const dongs = [...getDongs('경기', sg), ...(EUP_MYEON[sg] || [])];
      for (const d of dongs) urls.push(`/지역별/${encodeURIComponent('경기')}/${esg}/${encodeURIComponent(d)}`);
    }
  }

  // 7. 학년-과목 96개 + 키워드 아티클 30개씩 (총 ~2880개) — 검색량 매우 높음
  for (const sl of ['elementary','middle','high']) {
    const max = sl === 'elementary' ? 6 : 3;
    for (let g = 1; g <= max; g++) {
      for (const s of sub8) {
        const es = encodeURIComponent(s);
        urls.push(`/grade/${sl}/${g}/${es}`);
        for (let i = 0; i < 30; i++) urls.push(`/grade/${sl}/${g}/${es}/article/${i}`);
      }
    }
  }

  // 8. 과목별 페이지 + 키워드 아티클 0~9 (~80개)
  for (const s of sub8) {
    const es = encodeURIComponent(s);
    urls.push(`/과목별/${es}`);
    for (let i = 0; i < 9; i++) urls.push(`/과목별/${es}/article/${i}`);
  }

  // 9. 회화 키워드 아티클 (~90개)
  for (const lang of ['english','chinese','japanese']) {
    for (let i = 0; i < 30; i++) urls.push(`/conversation/${lang}/article/${i}`);
  }

  // 10. 학습가이드 (~30개)
  for (let i = 0; i < 30; i++) urls.push(`/학습가이드/article/${i}`);

  return urls;
}

// 3개 검색엔진 동시 호출 (네이버/Bing/Yandex)
async function pingIndexNow3Engines(urlList) {
  const body = JSON.stringify({
    host: SITE_HOST,
    key: INDEXNOW_KEY,
    keyLocation: `https://${SITE_HOST}/${INDEXNOW_KEY}.txt`,
    urlList
  });
  const headers = { 'Content-Type': 'application/json; charset=utf-8' };
  const endpoints = [
    { name: 'naver',  url: 'https://api.searchadvisor.naver.com/indexnow' },
    { name: 'bing',   url: 'https://www.bing.com/indexnow' },
    { name: 'yandex', url: 'https://yandex.com/indexnow' }
  ];
  const results = await Promise.all(endpoints.map(async ep => {
    try {
      const res = await fetch(ep.url, { method: 'POST', headers, body });
      return { engine: ep.name, status: res.status, ok: (res.status === 200 || res.status === 202) };
    } catch (e) {
      return { engine: ep.name, status: 0, ok: false, error: String(e).slice(0, 100) };
    }
  }));
  return results;
}

// 자동 색인 1회 실행 (오늘의 50개 처리)
async function runAutoIndexBatch(env) {
  if (!env || !env.INDEX_STATE) {
    return { ok: false, error: 'KV namespace INDEX_STATE 미설정' };
  }
  const queue = buildPriorityQueue();
  const total = queue.length;
  const offsetStr = await env.INDEX_STATE.get('offset');
  const offset = parseInt(offsetStr || '0') % total;
  const batchSize = 50;
  const batch = queue.slice(offset, offset + batchSize);
  // 회전 처리: 끝에 도달하면 앞에서 채움
  if (batch.length < batchSize) {
    batch.push(...queue.slice(0, batchSize - batch.length));
  }
  const fullUrls = batch.map(p => `https://${SITE_HOST}${p}`);

  // 3개 엔진 동시 호출
  const results = await pingIndexNow3Engines(fullUrls);
  const naverResult = results.find(r => r.engine === 'naver');
  const naverOk = naverResult && naverResult.ok;

  // 네이버 실패시 ALL_FAILED 큐에 모든 URL 추가 (옵션 2: 형이 직접 판단)
  const failedRaw = await env.INDEX_STATE.get('all_failed');
  const allFailed = failedRaw ? JSON.parse(failedRaw) : [];
  if (!naverOk) {
    const ts = new Date().toISOString();
    const status = naverResult ? naverResult.status : 0;
    for (const u of fullUrls) {
      allFailed.push({ url: u, status, ts });
    }
    await env.INDEX_STATE.put('all_failed', JSON.stringify(allFailed.slice(-500))); // 최근 500개만 유지
  }

  // offset 진행 (실패 여부 무관 - 옵션 2: 진행은 계속, 실패는 별도 큐)
  const newOffset = (offset + batchSize) % total;
  await env.INDEX_STATE.put('offset', String(newOffset));

  // 통계 업데이트
  const statsRaw = await env.INDEX_STATE.get('stats');
  const stats = statsRaw ? JSON.parse(statsRaw) : { totalProcessed: 0, totalFailed: 0, runs: 0, cycleStartedAt: new Date().toISOString() };
  stats.totalProcessed += fullUrls.length;
  if (!naverOk) stats.totalFailed += fullUrls.length;
  stats.runs += 1;
  stats.lastRunAt = new Date().toISOString();
  stats.lastOffset = offset;
  stats.lastBatchSize = batch.length;
  stats.lastResults = results;
  if (newOffset < offset) stats.cycleStartedAt = new Date().toISOString(); // 한 바퀴 돔
  await env.INDEX_STATE.put('stats', JSON.stringify(stats));

  return {
    ok: true,
    offset, newOffset, total,
    batchSize: fullUrls.length,
    results,
    naverOk,
    failedQueueSize: allFailed.length
  };
}

export default {
  async fetch(request, env) {
    const url = new URL(request.url);
    const pathname = url.pathname;

    // ===== v90: 자동 색인 시스템 API =====
    // /api/auto-index : 수동 트리거 (오늘의 50개 즉시 실행)
    // /api/auto-index?retry=failed : 실패 큐만 재시도
    if (pathname === '/api/auto-index') {
      if (!env || !env.INDEX_STATE) {
        return new Response(JSON.stringify({
          error: 'Cloudflare KV "INDEX_STATE" namespace 미설정. wrangler.toml 또는 대시보드에서 KV 바인딩을 추가해주세요.'
        }, null, 2), { status: 500, headers: { 'Content-Type': 'application/json' } });
      }
      const retry = url.searchParams.get('retry');
      if (retry === 'failed') {
        // 실패 큐만 재시도 (형이 직접 트리거)
        const failedRaw = await env.INDEX_STATE.get('all_failed');
        const allFailed = failedRaw ? JSON.parse(failedRaw) : [];
        if (allFailed.length === 0) {
          return new Response(JSON.stringify({ ok: true, message: '실패 큐가 비어있습니다.' }, null, 2),
            { headers: { 'Content-Type': 'application/json' } });
        }
        // 한번에 최대 50개씩만 재시도
        const retryBatch = allFailed.slice(0, 50).map(x => x.url);
        const results = await pingIndexNow3Engines(retryBatch);
        const naverResult = results.find(r => r.engine === 'naver');
        const naverOk = naverResult && naverResult.ok;
        if (naverOk) {
          // 성공: 재시도한 URL들을 실패 큐에서 제거
          const retried = new Set(retryBatch);
          const remaining = allFailed.filter(x => !retried.has(x.url));
          await env.INDEX_STATE.put('all_failed', JSON.stringify(remaining));
          return new Response(JSON.stringify({
            ok: true, retried: retryBatch.length, results,
            failedRemaining: remaining.length
          }, null, 2), { headers: { 'Content-Type': 'application/json' } });
        } else {
          return new Response(JSON.stringify({
            ok: false, retried: retryBatch.length, results,
            message: '재시도 실패. 큐 유지.'
          }, null, 2), { headers: { 'Content-Type': 'application/json' } });
        }
      }
      // 일반 트리거: 오늘의 50개 처리
      const result = await runAutoIndexBatch(env);
      return new Response(JSON.stringify(result, null, 2),
        { headers: { 'Content-Type': 'application/json; charset=utf-8' } });
    }

    // /api/index-stats : 통계 + 실패 큐 확인
    if (pathname === '/api/index-stats') {
      if (!env || !env.INDEX_STATE) {
        return new Response(JSON.stringify({ error: 'KV INDEX_STATE 미설정' }, null, 2),
          { status: 500, headers: { 'Content-Type': 'application/json' } });
      }
      const offsetStr = await env.INDEX_STATE.get('offset');
      const statsRaw = await env.INDEX_STATE.get('stats');
      const failedRaw = await env.INDEX_STATE.get('all_failed');
      const queue = buildPriorityQueue();
      const offset = parseInt(offsetStr || '0');
      const allFailed = failedRaw ? JSON.parse(failedRaw) : [];
      const stats = statsRaw ? JSON.parse(statsRaw) : null;

      // 응답코드별 그룹화 (형이 4xx/5xx 구분 쉽게)
      const failedByStatus = {};
      for (const f of allFailed) {
        const k = String(f.status || '0');
        if (!failedByStatus[k]) failedByStatus[k] = [];
        failedByStatus[k].push(f);
      }

      // 다음 처리 예정 10개 미리보기
      const upcoming = queue.slice(offset, offset + 10).map(p => `https://${SITE_HOST}${p}`);

      return new Response(JSON.stringify({
        queue: { total: queue.length, currentOffset: offset, progressPercent: ((offset / queue.length) * 100).toFixed(1) },
        stats,
        failed: { count: allFailed.length, byStatus: failedByStatus },
        upcoming
      }, null, 2), { headers: { 'Content-Type': 'application/json; charset=utf-8' } });
    }

    if (pathname === '/api/inquiry' && request.method === 'POST') {
      try {
        const data = await request.json();
        const name = String(data.name || '').slice(0, 50).trim();
        const phone = String(data.phone || '').slice(0, 20).trim();
        const grades = Array.isArray(data.grades) ? data.grades.slice(0, 15).map(g => String(g).slice(0, 20)) : [];
        const subjects = Array.isArray(data.subjects) ? data.subjects.slice(0, 15).map(s => String(s).slice(0, 20)) : [];
        const address = String(data.address || '').slice(0, 200).trim();
        const addressDetail = String(data.addressDetail || '').slice(0, 100).trim();
        const message = String(data.message || '').slice(0, 1000).trim();

        if (!name || !phone || !grades.length || !subjects.length || !address) {
          return new Response(JSON.stringify({error: '필수 항목이 누락되었습니다.'}), { status: 400, headers: {'Content-Type': 'application/json'} });
        }

        const esc = s => String(s||'').replace(/[&<>"']/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'}[c]));

        const resendKey = env && env.RESEND_API_KEY;
        if (!resendKey) {
          return new Response(JSON.stringify({error: '서버 설정 오류 (API 키 미설정)'}), { status: 500, headers: {'Content-Type': 'application/json'} });
        }
        const fromAddr = (env && env.RESEND_FROM) || 'onboarding@resend.dev';
        const toAddr = (env && env.INQUIRY_TO) || 'a01048275592@gmail.com';
        const nowKST = new Date().toLocaleString('ko-KR', { timeZone: 'Asia/Seoul' });

        const htmlBody = `<div style="font-family:-apple-system,'Noto Sans KR',sans-serif;max-width:640px;margin:0 auto;background:#fff;border:1px solid #e2e8f0;border-radius:12px;overflow:hidden;">
          <div style="background:linear-gradient(135deg,#312e81,#6366f1);padding:28px 24px;color:#fff;">
            <h2 style="margin:0;font-size:22px;">🎓 체험 수업 신청 접수</h2>
            <p style="margin:6px 0 0;opacity:0.9;font-size:13px;">anhani.com</p>
          </div>
          <div style="padding:24px;">
            <table style="width:100%;border-collapse:collapse;font-size:14px;">
              <tr><td style="padding:12px;background:#f1f5f9;font-weight:700;width:110px;border-bottom:1px solid #e2e8f0;">학생 이름</td><td style="padding:12px;border-bottom:1px solid #e2e8f0;">${esc(name)}</td></tr>
              <tr><td style="padding:12px;background:#f1f5f9;font-weight:700;border-bottom:1px solid #e2e8f0;">연락처</td><td style="padding:12px;border-bottom:1px solid #e2e8f0;"><a href="tel:${esc(phone)}" style="color:#0369a1;text-decoration:none;">${esc(phone)}</a></td></tr>
              <tr><td style="padding:12px;background:#f1f5f9;font-weight:700;border-bottom:1px solid #e2e8f0;">학년</td><td style="padding:12px;border-bottom:1px solid #e2e8f0;">${esc(grades.join(', '))}</td></tr>
              <tr><td style="padding:12px;background:#f1f5f9;font-weight:700;border-bottom:1px solid #e2e8f0;">희망 과목</td><td style="padding:12px;border-bottom:1px solid #e2e8f0;">${esc(subjects.join(', '))}</td></tr>
              <tr><td style="padding:12px;background:#f1f5f9;font-weight:700;border-bottom:1px solid #e2e8f0;">주소</td><td style="padding:12px;border-bottom:1px solid #e2e8f0;">${esc(address)}${addressDetail ? ' ' + esc(addressDetail) : ''}</td></tr>
              <tr><td style="padding:12px;background:#f1f5f9;font-weight:700;vertical-align:top;">문의사항</td><td style="padding:12px;white-space:pre-wrap;line-height:1.6;">${esc(message) || '(없음)'}</td></tr>
            </table>
            <p style="color:#64748b;font-size:12px;margin:20px 0 0;text-align:right;">📅 접수 시각: ${nowKST}</p>
          </div>
        </div>`;

        const resendRes = await fetch('https://api.resend.com/emails', {
          method: 'POST',
          headers: { 'Authorization': 'Bearer ' + resendKey, 'Content-Type': 'application/json' },
          body: JSON.stringify({
            from: fromAddr,
            to: [toAddr],
            subject: '[anhani.com] 체험 수업 신청 - ' + name,
            html: htmlBody
          })
        });

        if (!resendRes.ok) {
          const errText = await resendRes.text();
          console.log('[Resend Error]', resendRes.status, errText);
          let userMsg = '이메일 발송 실패';
          let detail = errText;
          try {
            const j = JSON.parse(errText);
            const errName = j.name || '';
            const errMessage = j.message || j.error || errText;
            detail = errMessage;
            if (errName === 'validation_error' && /testing emails/i.test(errMessage)) {
              userMsg = 'Resend 무료 플랜: 가입한 본인 이메일로만 수신 가능. 도메인 인증 필요';
            } else if (/domain/i.test(errMessage) && /verif/i.test(errMessage)) {
              userMsg = '발송 도메인 미인증. Resend에서 도메인 인증 필요';
            } else if (errName === 'invalid_api_key' || resendRes.status === 401) {
              userMsg = 'RESEND_API_KEY가 잘못되었습니다';
            } else if (resendRes.status === 403) {
              userMsg = 'Resend API 키 권한 부족 (Sending access 필요)';
            } else {
              userMsg = '이메일 발송 실패: ' + errMessage;
            }
          } catch(e) {}
          return new Response(JSON.stringify({error: userMsg, detail: detail, status: resendRes.status}), { status: 500, headers: {'Content-Type': 'application/json'} });
        }

        return new Response(JSON.stringify({success: true}), { headers: {'Content-Type': 'application/json'} });
      } catch (err) {
        return new Response(JSON.stringify({error: '처리 중 오류가 발생했습니다.'}), { status: 500, headers: {'Content-Type': 'application/json'} });
      }
    }

    if (pathname === '/version') {
      return new Response('v90-auto-index', { headers: { 'Content-Type': 'text/plain' } });
    }

    if (pathname === '/indexnow-auto') {
      if (INDEXNOW_KEY === 'PUT_YOUR_INDEXNOW_KEY_HERE') {
        return new Response('IndexNow 키 미설정', { status: 400 });
      }
      const offset = parseInt(url.searchParams.get('offset') || '0');
      const chunkSize = 10000;
      const allUrls = getAllUrls();
      const total = allUrls.length;

      if (offset >= total) {
        return new Response(`<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8"><title>IndexNow 완료</title><style>body{font-family:'Noto Sans KR',sans-serif;background:#f8fafc;display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0;padding:20px}.box{background:#fff;border-radius:16px;padding:48px;box-shadow:0 4px 24px rgba(0,0,0,.06);text-align:center;max-width:480px}h1{color:#16a34a;font-size:32px;margin-bottom:16px}p{color:#64748b;font-size:16px;line-height:1.7;margin-bottom:8px}.stat{font-size:48px;font-weight:900;color:#16a34a;margin:24px 0}a{display:inline-block;margin-top:24px;padding:12px 28px;background:#6366f1;color:#fff;text-decoration:none;border-radius:8px;font-weight:700}</style></head><body>
          <div class="box">
            <h1>🎉 IndexNow 제출 완료!</h1>
            <div class="stat">${total.toLocaleString()}</div>
            <p>모든 URL이 네이버 IndexNow에 성공적으로 제출되었습니다.</p>
            <p>네이버 검색에 반영되기까지 보통 1~7일 정도 걸립니다.</p>
            <a href="/">홈으로</a>
          </div>
        </body></html>`, { headers: {'Content-Type':'text/html;charset=utf-8'} });
      }

      const chunk = allUrls.slice(offset, offset + chunkSize)
        .map(u => `https://${SITE_HOST}${u}`);
      let naverStatus = 0;
      let errMsg = '';
      try {
        const res = await fetch('https://api.searchadvisor.naver.com/indexnow', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json; charset=utf-8' },
          body: JSON.stringify({
            host: SITE_HOST,
            key: INDEXNOW_KEY,
            keyLocation: `https://${SITE_HOST}/${INDEXNOW_KEY}.txt`,
            urlList: chunk
          })
        });
        naverStatus = res.status;
      } catch (e) {
        errMsg = String(e);
      }

      const nextOffset = offset + chunkSize;
      const completed = Math.min(nextOffset, total);
      const percent = Math.round((completed / total) * 100);
      const statusOk = (naverStatus === 200 || naverStatus === 202);

      return new Response(`<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8">
        <title>IndexNow 진행 중... ${percent}%</title>
        <meta http-equiv="refresh" content="3;url=/indexnow-auto?offset=${nextOffset}">
        <style>body{font-family:'Noto Sans KR',sans-serif;background:#f8fafc;display:flex;align-items:center;justify-content:center;min-height:100vh;margin:0;padding:20px}.box{background:#fff;border-radius:16px;padding:40px;box-shadow:0 4px 24px rgba(0,0,0,.06);text-align:center;max-width:520px;width:100%}h1{color:#0f172a;font-size:24px;margin-bottom:24px}.progress{background:#e2e8f0;border-radius:999px;height:14px;overflow:hidden;margin:20px 0}.bar{background:linear-gradient(90deg,#6366f1,#8b5cf6);height:100%;border-radius:999px;transition:width .3s}.stat{font-size:32px;font-weight:900;color:#6366f1;margin:8px 0}.meta{color:#64748b;font-size:14px;margin:6px 0}.ok{color:#16a34a;font-weight:700}.err{color:#dc2626;font-weight:700}.spin{display:inline-block;width:18px;height:18px;border:3px solid #e2e8f0;border-top-color:#6366f1;border-radius:50%;animation:s .8s linear infinite;vertical-align:middle;margin-right:6px}@keyframes s{to{transform:rotate(360deg)}}</style></head><body>
          <div class="box">
            <h1><span class="spin"></span> IndexNow 자동 제출 중...</h1>
            <div class="stat">${percent}%</div>
            <div class="progress"><div class="bar" style="width:${percent}%"></div></div>
            <p class="meta">${completed.toLocaleString()} / ${total.toLocaleString()} URL 처리</p>
            <p class="meta">현재 청크: ${chunk.length.toLocaleString()}개 제출 →
              ${statusOk ? `<span class="ok">✓ 네이버 응답 ${naverStatus}</span>` : `<span class="err">⚠ 응답 ${naverStatus} ${errMsg}</span>`}</p>
            <p class="meta" style="margin-top:20px;color:#94a3b8;font-size:12px;">3초 후 다음 청크 자동 진행 (이 창을 닫지 마세요)</p>
          </div>
        </body></html>`, { headers: {'Content-Type':'text/html;charset=utf-8'} });
    }

    if (INDEXNOW_KEY !== 'PUT_YOUR_INDEXNOW_KEY_HERE' &&
        pathname === `/${INDEXNOW_KEY}.txt`) {
      return new Response(INDEXNOW_KEY, {
        headers: { 'Content-Type': 'text/plain; charset=utf-8' }
      });
    }

    if (pathname === '/indexnow-submit') {
      if (INDEXNOW_KEY === 'PUT_YOUR_INDEXNOW_KEY_HERE') {
        return new Response(JSON.stringify({
          error: 'INDEXNOW_KEY가 설정되지 않았습니다. index.js 상단의 INDEXNOW_KEY를 수정하세요.'
        }, null, 2), {
          status: 400,
          headers: { 'Content-Type': 'application/json; charset=utf-8' }
        });
      }
      const offset = parseInt(url.searchParams.get('offset') || '0');
      const chunkSize = 10000;
      const allUrls = getAllUrls();
      const chunk = allUrls.slice(offset, offset + chunkSize)
        .map(u => `https://${SITE_HOST}${u}`);

      if (chunk.length === 0) {
        return new Response(JSON.stringify({
          done: true,
          message: '모든 URL 제출 완료',
          total: allUrls.length
        }, null, 2), {
          headers: { 'Content-Type': 'application/json; charset=utf-8' }
        });
      }

      let naverStatus = 0;
      let naverResponse = '';
      try {
        const res = await fetch('https://api.searchadvisor.naver.com/indexnow', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json; charset=utf-8' },
          body: JSON.stringify({
            host: SITE_HOST,
            key: INDEXNOW_KEY,
            keyLocation: `https://${SITE_HOST}/${INDEXNOW_KEY}.txt`,
            urlList: chunk
          })
        });
        naverStatus = res.status;
        naverResponse = await res.text();
      } catch (e) {
        naverResponse = String(e);
      }

      const nextOffset = offset + chunkSize;
      const nextUrl = nextOffset < allUrls.length
        ? `https://${SITE_HOST}/indexnow-submit?offset=${nextOffset}`
        : null;

      return new Response(JSON.stringify({
        submitted: chunk.length,
        offset: offset,
        progress: `${Math.min(nextOffset, allUrls.length).toLocaleString()} / ${allUrls.length.toLocaleString()}`,
        naver_status: naverStatus,
        naver_response: naverResponse.substring(0, 500),
        next_url: nextUrl,
        next_action: nextUrl ? '👉 위 next_url을 브라우저에서 다시 열어주세요' : '🎉 모든 제출 완료!'
      }, null, 2), {
        headers: { 'Content-Type': 'application/json; charset=utf-8' }
      });
    }

    if (pathname === '/robots.txt') {
      return new Response(robotsTxt(), { headers: { 'Content-Type': 'text/plain; charset=utf-8' } });
    }

    if (pathname === '/체험신청' || pathname === '/inquiry' || pathname === '/무료상담' || pathname === '/무료체험'
        || pathname === encodeURI('/체험신청') || pathname === encodeURI('/무료상담') || pathname === encodeURI('/무료체험')) {
      return new Response(renderInquiryPage(), {
        headers: { 'Content-Type': 'text/html;charset=utf-8' }
      });
    }

    if (pathname === '/favicon.ico') {
      const b64 = FAVICON_URI.split(',')[1];
      const bin = atob(b64);
      const bytes = new Uint8Array(bin.length);
      for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
      return new Response(bytes, {
        headers: {
          'Content-Type': 'image/x-icon',
          'Cache-Control': 'public, max-age=604800'
        }
      });
    }

    if (pathname === '/favicon.png' || pathname === '/apple-touch-icon.png' || pathname === '/apple-touch-icon-precomposed.png') {
      const b64 = FAVICON_URI.split(',')[1];
      const bin = atob(b64);
      const bytes = new Uint8Array(bin.length);
      for (let i = 0; i < bin.length; i++) bytes[i] = bin.charCodeAt(i);
      return new Response(bytes, {
        headers: {
          'Content-Type': 'image/png',
          'Cache-Control': 'public, max-age=604800'
        }
      });
    }

    if (pathname === '/rss' || pathname === '/rss.xml' || pathname === '/feed') {
      return new Response(generateRSS(), { headers: { 'Content-Type': 'application/rss+xml; charset=utf-8' } });
    }

    if (pathname === '/sitemap.xml') {
      const allUrls = getAllUrls();
      if (allUrls.length > 10000) {
        return new Response(generateSitemapIndex(allUrls.length), {
          headers: { 'Content-Type': 'application/xml; charset=utf-8' }
        });
      }
      return new Response(generateSitemap(), {
        headers: { 'Content-Type': 'application/xml; charset=utf-8' }
      });
    }

    const sitemapMatch = pathname.match(/^\/sitemap-(\d+)\.xml$/);
    if (sitemapMatch) {
      const part = parseInt(sitemapMatch[1]);
      return new Response(generateSitemapPart(part), {
        headers: { 'Content-Type': 'application/xml; charset=utf-8' }
      });
    }

    if (pathname === '/' || pathname === '') {
      return new Response(renderHomepage(), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }

    if (pathname === '/%EC%A7%80%EC%97%AD%EB%B3%84' || pathname === '/지역별') {
      return new Response(renderRegionList(), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }

    const regionPath = decodeURIComponent(pathname);
    // /지역별/{sido}/{sigungu}/{dong}/{lvl}/{subj}  - 학년+과목
    const dlsMatch = regionPath.match(/^\/지역별\/([^\/]+)\/([^\/]+)\/([^\/]+)\/([^\/]+)\/([^\/]+)$/);
    if (dlsMatch) {
      const [, sido, sg, dong, lvl, subj] = dlsMatch;
      if (REGIONS[sido]) {
        const html = renderDongCategoryPage(sido, sg, dong, 'lsubj', lvl, subj);
        if (html) return new Response(html, {
          headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
        });
      }
    }
    // /지역별/{sido}/{sigungu}/{dong}/과목/{subj}  또는  /학년/{lvl}
    const dcatMatch = regionPath.match(/^\/지역별\/([^\/]+)\/([^\/]+)\/([^\/]+)\/(과목|학년)\/([^\/]+)$/);
    if (dcatMatch) {
      const [, sido, sg, dong, cat, val] = dcatMatch;
      if (REGIONS[sido]) {
        const html = renderDongCategoryPage(sido, sg, dong, cat === '과목' ? 'subj' : 'lvl', val);
        if (html) return new Response(html, {
          headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
        });
      }
    }
    // /지역별/{sido}/{sigungu}/{dong}  - 기본 동 페이지 (학년별로 연결)
    const dongMatch = regionPath.match(/^\/지역별\/([^\/]+)\/([^\/]+)\/([^\/]+)$/);
    if (dongMatch) {
      const [, sido, sg, dong] = dongMatch;
      if (REGIONS[sido]) {
        const allDongs = [...getDongs(sido, sg), ...(EUP_MYEON[sg]||[])];
        if (allDongs.includes(dong)) {
          const html = renderDongCategoryPage(sido, sg, dong, 'main');
          if (html) return new Response(html, {
            headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
          });
        }
      }
    }
    const sgCatMatch = regionPath.match(/^\/지역별\/([^\/]+)\/([^\/]+)\/(과목|학년)\/([^\/]+)$/);
    if (sgCatMatch) {
      const [, sido, sg, cat, val] = sgCatMatch;
      if (REGIONS[sido]) {
        const html = renderSigunguDetail(sido, sg, cat, val);
        if (html) return new Response(html, {headers:{'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}});
      }
    }
    const sgMatch = regionPath.match(/^\/지역별\/([^\/]+)\/([^\/]+)$/);
    if (sgMatch) {
      const [, sido, sg] = sgMatch;
      if (REGIONS[sido]) {
        const html = renderSigunguDetail(sido, sg);
        if (html) return new Response(html, {
          headers: {'Content-Type':'text/html;charset=utf-8'}
        });
        const html2 = renderRegionDetail(sido);
        if (html2) return new Response(html2, { headers: {'Content-Type':'text/html;charset=utf-8'} });
      }
    }
    const regionMatch = regionPath.match(/^\/지역별\/(.+)$/);
    if (regionMatch) {
      const region = regionMatch[1];
      if (REGIONS[region]) {
        const html = renderRegionDetail(region);
        if (html) return new Response(html, { headers: {'Content-Type':'text/html;charset=utf-8'} });
      }
    }

    if (pathname === '/%EA%B3%BC%EB%AA%A9%EB%B3%84' || pathname === '/과목별') {
      return new Response(renderSubjectList(), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }
    const subjArticleMatch = decodeURIComponent(pathname).match(/^\/과목별\/(.+?)\/article\/(\d+)$/);
    if (subjArticleMatch) {
      const subj = subjArticleMatch[1];
      if (SUBJECTS.includes(subj)) {
        const html = renderSubjectArticle(subj, subjArticleMatch[2]);
        if (html) return new Response(html, {
          headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
        });
      }
    }
    const subjDetailMatch = decodeURIComponent(pathname).match(/^\/과목별\/(.+)$/);
    if (subjDetailMatch) {
      const subj = subjDetailMatch[1];
      if (SUBJECTS.includes(subj)) {
        const html = renderSubjectDetail(subj);
        if (html) return new Response(html, {
          headers: {'Content-Type':'text/html;charset=utf-8'}
        });
      }
    }

    if (pathname === '/%ED%95%99%EB%85%84%EB%B3%84' || pathname === '/학년별') {
      return new Response(renderGradeMain(), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }

    if (pathname === '/%ED%95%99%EA%B5%90%EA%B8%89%EB%B3%84' || pathname === '/학교급별') {
      return new Response(renderLevelList(), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }

    const decodedPathL = decodeURIComponent(pathname);
    if(decodedPathL==='/학교급별/elem')return new Response(renderElemMain(),{headers:{'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}});
    const eA=decodedPathL.match(/^\/학교급별\/elem\/([^\/]+)\/([^\/]+)\/([^\/]+)\/article\/(\d+)$/);
    if(eA){const h=renderElemArticle(eA[1],eA[2],eA[3],eA[4]);if(h)return new Response(h,{headers:{'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}});}
    const eS=decodedPathL.match(/^\/학교급별\/elem\/([^\/]+)\/([^\/]+)\/([^\/]+)$/);
    if(eS){const h=renderElemSchool(eS[1],eS[2],eS[3]);if(h)return new Response(h,{headers:{'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}});}
    const eG=decodedPathL.match(/^\/학교급별\/elem\/([^\/]+)\/([^\/]+)$/);
    if(eG){const h=renderElemSigungu(eG[1],eG[2]);if(h)return new Response(h,{headers:{'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}});}
    const eD=decodedPathL.match(/^\/학교급별\/elem\/([^\/]+)$/);
    if(eD){const h=renderElemSido(eD[1]);if(h)return new Response(h,{headers:{'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}});}
    const schLvMatch = decodedPathL.match(/^\/학교급별\/(middle|high)$/);
    if (schLvMatch) {
      return new Response(renderSchoolLevelMain(schLvMatch[1]), {
        headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
      });
    }

    const schSidoMatch = decodedPathL.match(/^\/학교급별\/(middle|high)\/([^\/]+)$/);
    if (schSidoMatch) {
      const sidoIdx = SIDO_LIST.indexOf(schSidoMatch[2]);
      if (sidoIdx >= 0) {
        const html = renderSchoolBySido(schSidoMatch[1], sidoIdx);
        if (html) return new Response(html, {
          headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
        });
      }
    }

    const schGugunMatch = decodedPathL.match(/^\/학교급별\/(middle|high)\/([^\/]+)\/([^\/]+)$/);
    if (schGugunMatch) {
      const sidoIdx = SIDO_LIST.indexOf(schGugunMatch[2]);
      if (sidoIdx >= 0) {
        const html = renderSchoolByGugun(schGugunMatch[1], sidoIdx, schGugunMatch[3]);
        if (html) return new Response(html, {
          headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
        });
      }
    }

    const schArtMatch = decodedPathL.match(/^\/(.+)-과외\/article\/(\d+)$/);
    if (schArtMatch) {
      const found = findSchoolByName(schArtMatch[1]);
      if (found) {
        const html = renderSchoolArticleNew(found.level, found.idx, schArtMatch[2]);
        if (html) return new Response(html, {
          headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
        });
      }
    }

    const schDetailMatch = decodedPathL.match(/^\/(.+)-과외$/);
    if (schDetailMatch) {
      const found = findSchoolByName(schDetailMatch[1]);
      if (found) {
        return new Response(renderSchoolDetail(found.level, found.idx), {
          headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
        });
      }
    }

    const decodedPath = decodeURIComponent(pathname);
    if (decodedPath === '/학원' || decodedPath === '/학원/전국지점') {
      return new Response(renderAcademyList(), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }

    const academyMatch = decodedPath.match(/^\/학원\/(.+)$/);
    if (academyMatch && academyMatch[1] !== '전국지점') {
      const centerName = academyMatch[1];
      const center = CENTERS.find(c => c.n === centerName);
      if (center) {
        return new Response(renderAcademyDetail(center), {
          headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
        });
      }
    }

    const schoolSubjMatch = decodedPath.match(/^\/학교학원\/([^\/]+)\/([^\/]+)\/([^\/]+)$/);
    if (schoolSubjMatch) {
      const center = CENTERS.find(c => c.n === schoolSubjMatch[1]);
      const schoolName = schoolSubjMatch[2];
      const subject = schoolSubjMatch[3];
      if (center && (center.s||[]).includes(subject)) {
        const allSchools = [
          ...(center.e ? center.e.split(/[,\s/]+/).filter(Boolean) : []),
          ...(center.m ? center.m.split(/[,\s/]+/).filter(Boolean) : []),
          ...(center.h ? center.h.split(/[,\s/]+/).filter(Boolean) : [])
        ].map(s => s.trim());
        if (allSchools.includes(schoolName)) {
          return new Response(renderSchoolSubjectAcademy(center, schoolName, subject), {
            headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
          });
        }
      }
    }

    const regionSubjMatch = decodedPath.match(/^\/지역학원\/([^\/]+)\/([^\/]+)\/([^\/]+)$/);
    if (regionSubjMatch) {
      const center = CENTERS.find(c => c.n === regionSubjMatch[1]);
      const region = regionSubjMatch[2];
      const subject = regionSubjMatch[3];
      if (center && (center.s||[]).includes(subject)) {
        const p = parseAcademyAddr(center.a);
        const valid = [...new Set([center.r, p.si, p.gu, p.dong].filter(Boolean))];
        if (valid.includes(region)) {
          return new Response(renderRegionSubjectAcademy(center, region, subject), {
            headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
          });
        }
      }
    }

    const articleMatch = pathname.match(/^\/grade\/(elementary|middle|high)\/(\d+)\/(.+)\/article\/(\d+)$/);
    if (articleMatch) {
      const subj = decodeURIComponent(articleMatch[3]);
      const validSubjs = getSubjectsForSchool(articleMatch[1]);
      if (validSubjs.includes(subj)) {
        const html = renderKeywordArticle(articleMatch[1], articleMatch[2], subj, articleMatch[4]);
        if (html) return new Response(html, {
          headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
        });
      }
    }

    const gradeSubjMatch = pathname.match(/^\/grade\/(elementary|middle|high)\/(\d+)\/(.+)$/);
    if (gradeSubjMatch) {
      const subj = decodeURIComponent(gradeSubjMatch[3]);
      const validSubjs = getSubjectsForSchool(gradeSubjMatch[1]);
      if (validSubjs.includes(subj)) {
        return new Response(renderGradeSubjectPage(gradeSubjMatch[1], gradeSubjMatch[2], subj), {
          headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
        });
      }
    }
    const gradeMatch = pathname.match(/^\/grade\/(elementary|middle|high)\/(\d+)$/);
    if (gradeMatch) {
      return new Response(renderGradePage(gradeMatch[1], gradeMatch[2]), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }

    const regionEN = {"seoul":"서울","gyeonggi":"경기","incheon":"인천","busan":"부산","daegu":"대구","daejeon":"대전","gwangju":"광주","ulsan":"울산","sejong":"세종","gangwon":"강원","chungbuk":"충북","chungnam":"충남","jeonbuk":"전북","jeonnam":"전남","gyeongbuk":"경북","gyeongnam":"경남","jeju":"제주"};
    const schoolMatch = pathname.match(/^\/school\/([a-z]+)$/);
    if (schoolMatch && regionEN[schoolMatch[1]]) {
      return new Response(renderSchoolPage(regionEN[schoolMatch[1]]), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }
    if (pathname === '/school') {
      return new Response(renderSchoolPage('서울'), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }

    const convMatch = pathname.match(/^\/conversation\/(english|chinese|japanese)$/);
    if (convMatch) {
      return new Response(renderConversationPage(convMatch[1]), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }
    if (decodedPath === '/외국어' || decodedPath === '/외국어/영어') {
      return new Response(renderConversationPage('english'), { headers: {'Content-Type':'text/html;charset=utf-8'} });
    }
    const enArticleMatch = decodedPath.match(/^\/외국어\/영어\/article\/(\d+)$/);
    if (enArticleMatch) {
      const html = renderEnglishArticle(enArticleMatch[1]);
      if (html) return new Response(html, {
        headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
      });
    }
    if (decodedPath === '/외국어/중국어') {
      return new Response(renderConversationPage('chinese'), { headers: {'Content-Type':'text/html;charset=utf-8'} });
    }
    const cnArticleMatch = decodedPath.match(/^\/외국어\/중국어\/article\/(\d+)$/);
    if (cnArticleMatch) {
      const html = renderChineseArticle(cnArticleMatch[1]);
      if (html) return new Response(html, {
        headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
      });
    }
    if (decodedPath === '/외국어/일본어') {
      return new Response(renderConversationPage('japanese'), { headers: {'Content-Type':'text/html;charset=utf-8'} });
    }
    const jpArticleMatch = decodedPath.match(/^\/외국어\/일본어\/article\/(\d+)$/);
    if (jpArticleMatch) {
      const html = renderJapaneseArticle(jpArticleMatch[1]);
      if (html) return new Response(html, {
        headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
      });
    }

    if (decodedPath === '/학습가이드') {
      return new Response(renderGuideList(), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }
    const guideArtMatch = decodedPath.match(/^\/학습가이드\/article\/(\d+)$/);
    if (guideArtMatch) {
      const gIdx = parseInt(guideArtMatch[1]);
      if (gIdx >= 0 && gIdx < GUIDE_ARTICLES.length) {
        const html = renderGuideArticle(gIdx);
        if (html) return new Response(html, {
          headers: {'Content-Type':'text/html;charset=utf-8','Cache-Control':'public,max-age=86400'}
        });
      }
    }

    if (pathname === '/video-lesson' || decodedPath === '/화상수업') {
      return new Response(renderVideoLesson(), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }

    if (decodedPath === '/서비스' || decodedPath === '/소개' || pathname === '/service') {
      return new Response(renderServicePage(), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }

    if (decodedPath === '/상담' || decodedPath === '/contact' || decodedPath === '/문의') {
      return new Response(renderContactPage(), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }

    if (decodedPath === '/유학') {
      return new Response(renderStudyAbroad(), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }

    if (decodedPath === '/상세' || decodedPath === '/landing' || decodedPath === '/서비스소개') {
      return new Response(renderLandingPage(), {
        headers: {'Content-Type':'text/html;charset=utf-8'}
      });
    }

    const parsed = parseUrl(pathname);
    if (parsed) {
      const regionInfo = findRegion(parsed.location);
      if (regionInfo.valid) {
        const html = renderPage(parsed.location, parsed.level, parsed.subject, regionInfo.parentRegion, pathname);
        return new Response(html, {
          headers: {
            'Content-Type': 'text/html; charset=utf-8',
            'Cache-Control': 'public, max-age=86400',
          }
        });
      }
    }

    return new Response(`<!DOCTYPE html><html lang="ko"><head><meta charset="UTF-8"><title>페이지를 찾을 수 없습니다 | 안하니</title></head><body style="font-family:sans-serif;text-align:center;padding:100px 20px;"><h1>404</h1><p>요청하신 페이지를 찾을 수 없습니다.</p><a href="/">홈으로 돌아가기</a></body></html>`, {
      status: 404,
      headers: {'Content-Type':'text/html;charset=utf-8'}
    });
  },

  // ===== v90: Cron Trigger 핸들러 =====
  // wrangler.toml의 [triggers] crons 설정에 의해 매일 KST 09:00 (UTC 00:00) 자동 실행
  async scheduled(event, env, ctx) {
    ctx.waitUntil(runAutoIndexBatch(env));
  }
};
